class Solution:
    def findTilt(self, root: Optional[TreeNode]) -> int:
        self.ans = 0
        def dfs(n):
            if not n: return 0
            l, r = dfs(n.left), dfs(n.right)
            self.ans += abs(l - r)
            return n.val + l + r
        dfs(root)
        return self.ans

