class Solution {
    int ans = 0;
    int dfs(TreeNode* n) {
        if (!n) return 0;
        int l = dfs(n->left), r = dfs(n->right);
        ans += abs(l - r);
        return n->val + l + r;
    }
public:
    int findTilt(TreeNode* root) {
        dfs(root);
        return ans;
    }
};
